query:
ALTER TABLE driver_profiles ADD COLUMN IF NOT EXISTS driver_code VARCHAR(8);
ALTER TABLE company_profiles ADD COLUMN IF NOT EXISTS company_code VARCHAR(8);
CREATE UNIQUE INDEX IF NOT EXISTS idx_driver_code ON driver_profiles(driver_code);
CREATE UNIQUE INDEX IF NOT EXISTS idx_company_code ON company_profiles(company_code);
CREATE TABLE IF NOT EXISTS driver_company_links (
  id INT AUTO_INCREMENT PRIMARY KEY,
  driver_profile_id INT NOT NULL,
  company_id INT NOT NULL,
  status ENUM('pending', 'active', 'declined', 'removed') NOT NULL DEFAULT 'pending',
  invited_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  responded_at TIMESTAMP NULL
);
CREATE UNIQUE INDEX IF NOT EXISTS idx_dcl_unique ON driver_company_links(driver_profile_id, company_id);
CREATE INDEX IF NOT EXISTS idx_dcl_company ON driver_company_links(company_id);
CREATE INDEX IF NOT EXISTS idx_dcl_driver ON driver_company_links(driver_profile_id);

